```javascript
// Constants
var TAU = 6.283;          // 2π
var PHI = 1.618;          // Golden ratio
var SQRT_HALF = 0.707;    // √(1/2)

// Simulation configuration
var config = {
    gravity: 4000,
    stiffion: 0.004,       // spring stiffness (default)
    dampingFriction: 0.92, // velocity damping
    centering: 0.0003,     // center-pulling force
    particleRate: 40,      // max particles
    particleSpeed: 0.04,
    deltaTime: 0.06
};

// --- NODES (graph vertices) ---
var nodes = [
    { id: "alpha",   label: "Alpha",   r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: "beta",    label: "Beta",    r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: "zeta",    label: "Zeta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// --- EDGES (spring connections between nodes) ---
var edges = [
    { a: "alpha", b: "beta",    rest: 160, k: 0.006 },
    { a: "alpha", b: "zeta",    rest: 160, k: 0.005 },
    { a: "alpha", b: "gamma",   rest: 170, k: 0.004 },
    { a: "alpha", b: "delta",   rest: 170, k: 0.004 },
    { a: "alpha", b: "epsilon", rest: 180, k: 0.003 },
    { a: "beta",  b: "zeta",    rest: 200, k: 0.002 },
    { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
    { a: "beta",  b: "epsilon", rest: 200, k: 0.002 }
];

// Camera system
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particle system
var particles = [];
var frameCount = 0;

// Find a node by ID
function findNode(id) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// Main physics simulation
function simulate() {
    // 1) REPULSION: All node pairs repel each other (like charged particles)
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = config.gravity / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2) SPRING FORCES: Connected nodes attract via springs (Hooke's law)
    for (var i = 0; i < edges.length; i++) {
        var nodeA = findNode(edges[i].a);
        var nodeB = findNode(edges[i].b);
        if (!nodeA || !nodeB) continue;
        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[i].rest;
        var force = (edges[i].k || config.stiffion) * displacement;
        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // 3) UPDATE POSITIONS: Apply damping, centering force, integrate velocity
    for (var i = 0; i < nodes.length; i++) {
        nodes[i].vx *= config.dampingFriction;     // damping
        nodes[i].vy *= config.dampingFriction;
        nodes[i].vx += (400 - nodes[i].x) * config.centering;  // pull toward center
        nodes[i].vy += (300 - nodes[i].y) * config.centering;
        nodes[i].x += nodes[i].vx;                 // integrate
        nodes[i].y += nodes[i].vy;
    }
}

// Spawn ambient particles from random nodes
function spawnParticles() {
    if (particles.length >= config.particleRate) return;
    var node = nodes[Math.floor(Math.random() * nodes.length)];
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT_HALF;
    particles.push({
        x: node.x,
        y: node.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + Math.random() * PHI * SQRT_HALF
    });
}

// Update and cull particles
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];
        p.vx *= 1 - config.particleSpeed * 0.125;
        p.vy *= 1 - config.particleSpeed * 0.125;
        p.x += p.vx;
        p.y += p.vy;
        p.age++;
        if (p.age > p.maxAge) particles.splice(i, 1);
    }
}

// Smooth camera interpolation
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * config.deltaTime;
    camera.y += (cameraTarget.y - camera.y) * config.deltaTime;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * config.deltaTime;
}

// Main loop
function tick() {
    simulate();
    updateParticles();
    updateCamera();
    if (frameCount % 3 === 0) spawnParticles();
    frameCount++;
}

setInterval(tick, 16); // ~60 FPS
```

## Summary

This is a **force-directed graph layout simulation** with decorative particles. Specifically:

| Component | What it does |
|-----------|-------------|
| **Nodes** | 6 named nodes (Alpha, Beta, Gamma, Delta, Zeta, Epsilon) with sizes indicating hierarchy |
| **Repulsion** | All nodes repel each other (inverse-square law, like electrostatic force) |
| **Springs** | 8 edges act as springs pulling connected nodes toward a rest distance (Hooke's law) |
| **Damping** | Velocity is multiplied by 0.92 each frame to prevent oscillation |
| **Centering** | A gentle force pulls all nodes toward (400, 300) |
| **Particles** | Cosmetic particles spawn from random nodes, drift outward, and fade/die after a lifetime |
| **Camera** | Smooth interpolation (lerp) toward a target position/zoom |
| **Loop** | Runs at ~60 FPS via `setInterval(..., 16)` |

This is essentially the **physics engine behind a node-graph visualization** (like D3.js force layouts), likely for rendering an interactive network diagram with ambient particle effects. There is **no rendering code** here — this is purely the simulation/state update. The drawing would happen elsewhere using these node/particle positions.
